// src/Dashboard.js
import React, { useEffect, useState } from "react";
import axios from "axios";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";

function Dashboard() {
  const [email, setEmail] = useState("");
  const [alerts, setAlerts] = useState([]);
  const [showHistory, setShowHistory] = useState(false);

  const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

  // Send SOS
  const sendSOS = () => {
    if (!email) {
      window.alert("Enter email first!");
      return;
    }

    navigator.geolocation.getCurrentPosition(async (pos) => {
      const latitude = pos.coords.latitude;
      const longitude = pos.coords.longitude;

      try {
        await axios.post(`${API_URL}/alert`, {
          email,
          latitude,
          longitude,
        });
        window.alert("SOS Sent 🚨");
        fetchAlerts();
      } catch (err) {
        console.error(err);
      }
    });
  };

  // Fetch Alerts
  const fetchAlerts = async () => {
    try {
      const res = await axios.get(`${API_URL}/alerts`);
      setAlerts(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchAlerts();
  }, []);

  return (
    <div style={{ textAlign: "center", padding: "20px" }}>
      <h1>Women Safety Dashboard 🚀</h1>

      <input
        placeholder="Enter Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        style={{ padding: "10px", marginBottom: "10px" }}
      />

      <br />

      <button
        onClick={sendSOS}
        style={{
          padding: "15px",
          fontSize: "18px",
          backgroundColor: "red",
          color: "white",
          border: "none",
          borderRadius: "10px",
        }}
      >
        🚨 SOS
      </button>

      <br />
      <br />

      <button onClick={() => setShowHistory(!showHistory)}>
        {showHistory ? "Hide History" : "Show History"}
      </button>

      {showHistory && (
        <>
          <h2>Alert History</h2>
          <h2>Live Map</h2>

          <MapContainer
            center={
              alerts.length
                ? [alerts[0].latitude, alerts[0].longitude]
                : [20, 77]
            }
            zoom={5}
            style={{ height: "300px", width: "80%", margin: "auto" }}
          >
            <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />

            {alerts.map((a) => (
              <Marker
                key={a._id}
                position={[a.latitude, a.longitude]}
              >
                <Popup>
                  📧 {a.email} <br />
                  📍 {a.latitude}, {a.longitude}
                </Popup>
              </Marker>
            ))}
          </MapContainer>

          {alerts.map((a) => (
            <div key={a._id} style={{ margin: "10px" }}>
              📧 {a.email} | 📍 {a.latitude}, {a.longitude}
            </div>
          ))}
        </>
      )}
    </div>
  );
}

export default Dashboard;
